import { HttpErrorResponse } from '@angular/common/http';
import { Component, OnInit, QueryList, ViewChildren } from '@angular/core';
import { FormBuilder, FormGroup } from '@angular/forms';
import { Router } from '@angular/router';
import { DataTableDirective } from 'angular-datatables';
import { Subject } from 'rxjs';
import { permissionsLabels } from 'src/app/shared/models/fmosNewRolePermissions';
import { ApiService } from 'src/app/shared/services/api.service';
import { RoleService } from 'src/app/shared/services/role.service';
import { ToastService } from 'src/app/shared/services/toast.service';
import Swal from 'sweetalert2';

@Component({
  selector: 'npr-user-gcc-ac-maintenance',
  templateUrl: './user-gcc-ac-maintenance.component.html',
  styleUrls: ['./user-gcc-ac-maintenance.component.scss']
})
export class UserGccAcMaintenanceComponent implements OnInit {
  userGlSummryForm: FormGroup;
  showList: boolean = false;
  enableButton: boolean = false;
  onbackSpace: boolean = false;
  userID: any;
  userName: any;
  usersList: any;
  transactionData: any;
  accountClassData: any;
  deleteGLResp: any;
  deleteaccResp: any;
  allowpermissions: any;
  disallowpermissions: any;
  dtOptions: DataTables.Settings[] = [];
  dtTrigger1: Subject<any> = new Subject<any>();
  dtTrigger2: Subject<any> = new Subject<any>();

  @ViewChildren(DataTableDirective)
  dtElements: QueryList<DataTableDirective>;
  allUserID: any;
  roleCodes = new permissionsLabels();
  

  constructor(private apiService: ApiService, private roleService:RoleService,
    private formBuilder: FormBuilder, private toastService: ToastService,private router : Router) { }

  ngOnInit(): void {
    this.dtOptions[0]= {
      pagingType: 'full_numbers',
      pageLength : 5,
      columnDefs: [ { type: 'date', 'targets': [3] } ],
      order: [[3, 'desc']],
      processing: true,
      lengthMenu: [[5, 10, 20, -1], [5, 10, 20, 30]],
      retrieve:true

    };
    this.dtOptions[1]= {
      pagingType: 'full_numbers',
      pageLength : 5,
      columnDefs: [ { type: 'date', 'targets': [3] } ],
      order: [[3, 'desc']],
      processing: true,
      lengthMenu: [[5, 10, 20, -1], [5, 10, 20, 30]],
      retrieve:true
      // columnDefs: [ { type: 'date', 'targets': [5] } ],
      // order: [[5, 'desc']],

    };


    this.userGlSummryForm = this.formBuilder.group({
      userId: [""],
    });
    this.getUserName();
    this.roleService.fetchScreenPermissions('User Account Restriction');
    this.roleService.screenLabelList.subscribe(message => this.roleCodes = message);
    console.log(this.roleCodes);

   
  }
  ngOnDestroy(): void {
    // Do not forget to unsubscribe the event
    this.dtTrigger1.unsubscribe();
    this.dtTrigger2.unsubscribe();
  }
  getUserName() {
    this.apiService.getUserName().subscribe(userName => {
      this.userName = userName.sort();
      this.usersList = [];
      this.allUserID = this.userName;
      var list = document.getElementById('allusers');
      this.allUserID.forEach(function (item) {
        var option = document.createElement('option');
        option.value = item;
        list.appendChild(option);
      });
      if (this.userName) {
        console.log(this.userName);
      } else {
        console.log("No name");
      }
    });
  }
  keyPress(user: any) {
    if (user) {
      this.showList = true;
      let list = this.userName.filter(option => option.includes(user));
      this.usersList = list;
    }
    else {
      this.showList = false;
      this.usersList = [];
    }
  }
  onOptionsSelected(event) {
    this.userID = event;
    if (this.userID) {
      this.userGlSummryForm.controls.userId.setValue(this.userID);
      this.showList = false;
      this.enableButton = true;
      console.log(this.userID);
    }
    else {
      this.enableButton = false;
    }
    
  }
  keyUpevent(event) {
    if (event.keyCode === 8) {
      this.enableButton = false;
    }
    else {
      this.onbackSpace = true;
    }
  }
  getGlTransactiondata() {
    
    const gltype = "GL";
    this.apiService.getUserIdGlData(this.userID,gltype).subscribe(transactiondata => {
      this.transactionData = transactiondata;
      if(this.transactionData.length=='0'){
        localStorage.removeItem('ALLOWUSER');
        localStorage.removeItem('DISALLOWUSER');
      }
      this.allowpermissions = this.transactionData.filter(
        (allow) => allow.permission === 'Allow');
        console.log(this.allowpermissions);
      this.disallowpermissions = this.transactionData.filter(
        (disallow) => disallow.permission === 'Disallow');
        console.log(this.disallowpermissions);
if(this.allowpermissions.length!='0'){
  console.log("AllowPermission");
  localStorage.setItem('ALLOWUSER',JSON.stringify(this.allowpermissions));
}
if(this.disallowpermissions.length!='0'){
  console.log(  this.disallowpermissions,"disallowpermissions");
  localStorage.setItem('DISALLOWUSER', JSON.stringify(this.disallowpermissions));
}
      this.dtTrigger1.next();
      console.log(this.transactionData);
      if (this.transactionData[0].userId != null) {
        // this.toastService.successMessage('Data Fetched Successfully!.', '');
        return;
      }
      else {
        // this.toastService.errorMessage('Failed to Fetch GL Code Summary Data!.', '');
        return;
      }
    });
    const actype = "AC";
    this.apiService.getUserIdAccData(this.userID,actype).subscribe(accountClass => {
      this.accountClassData = accountClass;
      if(this.accountClassData.length=='0'){
        localStorage.removeItem('ALLOWACCCLASSUSER');
        localStorage.removeItem('DISALLOWACCCLASSUSER');
      }
      this.allowpermissions = this.accountClassData.filter(
        (allow) => allow.permission === 'Allow');
        console.log(this.allowpermissions);
      this.disallowpermissions = this.accountClassData.filter(
        (disallow) => disallow.permission === 'Disallow');
        console.log(this.disallowpermissions);
if(this.allowpermissions.length!='0'){
  console.log("AllowPermission");
  localStorage.setItem('ALLOWACCCLASSUSER',JSON.stringify(this.allowpermissions));
}
if(this.disallowpermissions.length!='0'){
  console.log(  this.disallowpermissions,"disallowpermissions");
  localStorage.setItem('DISALLOWACCCLASSUSER', JSON.stringify(this.disallowpermissions));
}
      this.dtTrigger2.next();
      console.log(this.accountClassData);
      if (this.accountClassData[0].userId ==null) {
        // this.toastService.errorMessage('Failed to Fetch Account Class Summary Data!', '');
      }
    });
  }
  deleteUserGLData(row) {
    console.log(row);
    const userID = row.userId
    this.apiService.deleteGlDataUser(row, userID).subscribe(res => {
      this.deleteGLResp = res;
      if (this.deleteGLResp) {
        // this.toastService.successMessage('Data Saved Successfully!.', '');
        Swal.fire({
          title: 'GL Code Record is Deleted',
          icon: 'success'
        });
        this.getGlTransactiondata();
      }
      else {
        // this.toastService.errorMessage('Failed to Save Data!', '');
        Swal.fire({
          title: 'Failed to Delete Data!',
          icon: 'error'
        });
      }
    },
      error => {
        if (HttpErrorResponse) {
          Swal.fire({
            text: 'Server Error!',
            icon: 'error'
          });
        }
      });

  }
  deleteaccountClassData(row) {
    console.log(row);
    const userID = row.userId
    this.apiService.deleteAcDataUser(row, userID).subscribe(res => {
      this.deleteaccResp = res;
    if (this.deleteaccResp) {
      // this.toastService.successMessage('Data Saved Successfully!.', '');
      Swal.fire({
        title: 'Account Class Record is Deleted',
        icon: 'success'
      });
      this.getGlTransactiondata();
    }
    else {
      // this.toastService.errorMessage('Failed to Save Data!', '');
      Swal.fire({
        title: 'Failed to Delete Data!',
        icon: 'error'
      });
    }
  },
    error => {
      if (HttpErrorResponse) {
        Swal.fire({
          text: 'Server Error!',
          icon: 'error'
        });
      }
    });
  }
  sendingUserGCCforEdit(data) { 
    localStorage.setItem('getuserGCCSummarydata', JSON.stringify(data));
        this.apiService.setUserGCCSummary({
          approvedEver :data.approvedEver,
          approvedStatus : data.approvedStatus,
          approvedTime: data.approvedTime,
          approverId: data.approverId,
          createdTime: data.createdTime,
          creatorId: data.creatorId,
          userGlCodeId: data.userGlCodeId,
          medUserGlCodeDetails: data.medUserGlCodeDetails,
          permission: data.permission,
          recordStatus: data.recordStatus,
          versionNo: data.versionNo,
          activeTab : 'true'
        });
        this.router.navigate(["/system-param-maintenance/user-gl-edit"]);
  }
  sendingUserACCforEdit(data) { 
    localStorage.setItem('getuserACCSummarydata', JSON.stringify(data));
        this.apiService.setUserACCSummary({
          approvedEver :data.approvedEver,
          approvedStatus : data.approvedStatus,
          approvedTime: data.approvedTime,
          approverId: data.approverId,
          createdTime: data.createdTime,
          creatorId: data.creatorId,
          userAccClassId: data.userAccClassId,
          medUserAccountClassDetails: data.medUserAccountClassDetails,
          permission: data.permission,
          recordStatus: data.recordStatus,
          versionNo: data.versionNo,
          activeTab : 'true'
        });
        this.router.navigate(["/system-param-maintenance/user-ac-edit"]);
  }
}
